description:
Implement the type-level renderer lookup - finding and executing renderers registered for specific types.

Location: crates/baml-bridge/src/prompt/world.rs

```rust
impl PromptWorld {
    /// Try type-level renderer for pv's type and style
    fn try_type_renderer(&self, pv: &PromptValue, style: &str) -> Result<Option<RenderOutput>, RenderError> {
        // Build renderer key from type
        let key = self.renderer_key_for_type(&pv.ty, style)?;

        // Look up in renderer db
        let renderer = match self.renderers.get(&key) {
            Some(r) => r,
            None => return Ok(None),  // No renderer for this type/style
        };

        // Execute renderer
        let result = self.execute_renderer(renderer, pv)?;
        Ok(Some(result))
    }

    fn renderer_key_for_type(&self, ty: &TypeIR, style: &str) -> Option<RendererKey> {
        match ty {
            TypeIR::Class { name, mode, .. } => {
                Some(RendererKey::for_class(name, *mode, style))
            }
            TypeIR::Enum { name, .. } => {
                Some(RendererKey::for_enum(name, style))
            }
            // Primitives don't have type-level renderers
            _ => None,
        }
    }

    fn execute_renderer(&self, renderer: &CompiledRenderer, pv: &PromptValue) -> RenderResult {
        match renderer {
            CompiledRenderer::Jinja { template_name } => {
                self.execute_jinja_renderer(template_name, pv)
            }
            CompiledRenderer::Func { f } => {
                f(pv, &pv.session)
            }
        }
    }

    fn execute_jinja_renderer(&self, template_name: &str, pv: &PromptValue) -> RenderResult {
        let template = self.jinja.get_template(template_name)
            .map_err(|e| RenderError { /* ... */ })?;

        // Build context: value = typed, ctx = session ctx
        let ctx = minijinja::context\! {
            value => pv.as_jinja_value(),
            ctx => pv.session.ctx.clone(),
        };

        let text = template.render(ctx)
            .map_err(|e| RenderError { /* ... */ })?;

        Ok(RenderOutput { text })
    }
}
```

Template context:
- value: the JinjaPromptValue (typed traversal)
- ctx: session context (max_output_chars, etc.)
